     *
     * <p>Examples: <br>
     * {1,2,3}.appendAll({4,5}) returns {1,2,3,4,5} <br>
     * emptyList.appendAll({1,2}) returns {1,2} <br>
     * {1,2}.appendAll(emptyList) returns {1,2}
     */
    GList<T> appendAll(GList<T> other);

